     1→/* ==========================================================================
     2→   Base Design System - Protocodus
     3→   ========================================================================== */
     4→:root {
     5→  /* Colors based on Logo */
     6→  --clr-bg: #FAFAFA;
     7→  --clr-text: #1A1A1A;
     8→  --clr-yellow: #FFC400;
     9→  --clr-mint: #00FFC3;
    10→  --clr-black: #1A1A1A;
    11→  --clr-white: #FFFFFF;
    12→  --clr-grey: #888888;
    13→
    14→  /* Typography */
    15→  --font-primary: 'Space Grotesk', sans-serif;
    16→
    17→  /* Layout & Spacing */
    18→  --container-width: 1120px;
    19→  --space-sm: 1rem;
    20→  --space-md: 2rem;
    21→  --space-lg: 4rem;
    22→  --space-xl: 7rem;
    23→
    24→  /* Aesthetics */
    25→  --border-radius: 0px;
    26→  --border-radius-pill: 999px;
    27→  --border-width: 2.5px;
    28→  --shadow-solid: 5px 5px 0px var(--clr-black);
    29→  --shadow-solid-hover: 2px 2px 0px var(--clr-black);
    30→  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    31→}
    32→
    33→/* Base Reset */
    34→*,
    35→*::before,
    36→*::after {
    37→  box-sizing: border-box;
    38→  margin: 0;
    39→  padding: 0;
    40→}
    41→
    42→html {
    43→  scroll-behavior: smooth;
    44→  -webkit-font-smoothing: antialiased;
    45→  -moz-osx-font-smoothing: grayscale;
    46→}
    47→
    48→body {
    49→  font-family: var(--font-primary);
    50→  color: var(--clr-text);
    51→  line-height: 1.7;
    52→  overflow-x: hidden;
    53→}
    54→
    55→/* Animated Background (p5.js) */
    56→.bg-animation-container {
    57→  position: fixed;
    58→  top: 0;
    59→  left: 0;
    60→  width: 100vw;
    61→  height: 100vh;
    62→  z-index: -1;
    63→  overflow: hidden;
    64→  pointer-events: none;
    65→  background-color: var(--clr-bg);
    66→}
    67→
    68→.bg-animation-container canvas {
    69→  display: block;
    70→  width: 100% !important;
    71→  height: 100% !important;
    72→}
    73→
    74→a {
    75→  text-decoration: none;
    76→  color: inherit;
    77→}
    78→
    79→ul {
    80→  list-style: none;
    81→}
    82→
    83→img,
    84→svg {
    85→  max-width: 100%;
    86→  display: block;
    87→}
    88→
    89→.container {
    90→  max-width: var(--container-width);
    91→  margin: 0 auto;
    92→  padding: 0 var(--space-md);
    93→}
    94→
    95→.section {
    96→  padding: var(--space-xl) 0;
    97→}
    98→
    99→/* ==========================================================================
   100→   Scroll Reveal Animation
   101→   ========================================================================== */
   102→.reveal {
   103→  opacity: 0;
   104→  transform: translateY(40px);
   105→  transition: opacity 0.8s cubic-bezier(0.16, 1, 0.3, 1),
   106→    transform 0.8s cubic-bezier(0.16, 1, 0.3, 1);
   107→}
   108→
   109→.reveal.visible {
   110→  opacity: 1;
   111→  transform: translateY(0);
   112→}
   113→
   114→/* Stagger children */
   115→.bento-grid .reveal:nth-child(2) {
   116→  transition-delay: 0.1s;
   117→}
   118→
   119→.bento-grid .reveal:nth-child(3) {
   120→  transition-delay: 0.2s;
   121→}
   122→
   123→.bento-grid .reveal:nth-child(4) {
   124→  transition-delay: 0.3s;
   125→}
   126→
   127→/* ==========================================================================
   128→   Buttons
   129→   ========================================================================== */
   130→.btn {
   131→  display: inline-flex;
   132→  align-items: center;
   133→  justify-content: center;
   134→  padding: 0.9rem 2rem;
   135→  font-weight: 700;
   136→  text-transform: uppercase;
   137→  letter-spacing: 1.5px;
   138→  border: var(--border-width) solid var(--clr-black);
   139→  transition: var(--transition);
   140→  font-size: 0.85rem;
   141→  font-family: var(--font-primary);
   142→  cursor: pointer;
   143→}
   144→
   145→.btn-primary {
   146→  background-color: var(--clr-yellow);
   147→  color: var(--clr-black);
   148→  box-shadow: var(--shadow-solid);
   149→}
   150→
   151→.btn-primary:hover {
   152→  box-shadow: var(--shadow-solid-hover);
   153→  transform: translate(3px, 3px);
   154→  background-color: var(--clr-mint);
   155→}
   156→
   157→.btn-outline {
   158→  background-color: var(--clr-white);
   159→  color: var(--clr-black);
   160→  box-shadow: var(--shadow-solid);
   161→}
   162→
   163→.btn-outline:hover {
   164→  box-shadow: var(--shadow-solid-hover);
   165→  transform: translate(3px, 3px);
   166→  background-color: var(--clr-yellow);
   167→}
   168→
   169→.btn-lg {
   170→  font-size: 1.05rem;
   171→  padding: 1.1rem 2.5rem;
   172→}
   173→
   174→/* ==========================================================================
   175→   Navbar
   176→   ========================================================================== */
   177→.navbar {
   178→  position: fixed;
   179→  top: 0;
   180→  left: 0;
   181→  width: 100%;
   182→  background-color: rgba(250, 250, 250, 0.92);
   183→  backdrop-filter: blur(12px);
   184→  -webkit-backdrop-filter: blur(12px);
   185→  border-bottom: var(--border-width) solid var(--clr-black);
   186→  z-index: 1000;
   187→  transition: var(--transition);
   188→}
   189→
   190→.navbar.scrolled {
   191→  padding: 0;
   192→}
   193→
   194→.nav-container {
   195→  display: flex;
   196→  justify-content: space-between;
   197→  align-items: center;
   198→  height: 80px;
   199→}
   200→
   201→.logo {
   202→  display: flex;
   203→  align-items: center;
   204→  gap: 0.75rem;
   205→}
   206→
   207→.logo-img {
   208→  height: 52px;
   209→  width: auto;
   210→}
   211→
   212→.logo-text {
   213→  font-size: 1.3rem;
   214→  font-weight: 800;
   215→  letter-spacing: 2px;
   216→}
   217→
   218→.nav-links {
   219→  display: flex;
   220→  align-items: center;
   221→  gap: 2.5rem;
   222→}
   223→
   224→.nav-link {
   225→  font-weight: 600;
   226→  font-size: 0.85rem;
   227→  text-transform: uppercase;
   228→  letter-spacing: 1px;
   229→  position: relative;
   230→  padding: 0.5rem 0;
   231→  color: var(--clr-text);
   232→}
   233→
   234→.nav-link::after {
   235→  content: '';
   236→  position: absolute;
   237→  bottom: 0;
   238→  left: 0;
   239→  width: 0%;
   240→  height: 2.5px;
   241→  background-color: var(--clr-yellow);
   242→  transition: var(--transition);
   243→}
   244→
   245→.nav-link:hover::after {
   246→  width: 100%;
   247→}
   248→
   249→.nav-btn {
   250→  background-color: var(--clr-yellow);
   251→  padding: 0.65rem 1.5rem;
   252→  border: var(--border-width) solid var(--clr-black);
   253→  font-weight: 700;
   254→  box-shadow: 3px 3px 0px var(--clr-black);
   255→  transition: var(--transition);
   256→  text-transform: uppercase;
   257→  font-size: 0.8rem;
   258→  letter-spacing: 1px;
   259→}
   260→
   261→.nav-btn:hover {
   262→  box-shadow: 1px 1px 0px var(--clr-black);
   263→  transform: translate(2px, 2px);
   264→  background-color: var(--clr-mint);
   265→}
   266→
   267→.mobile-menu-btn {
   268→  display: none;
   269→  background: none;
   270→  border: none;
   271→  flex-direction: column;
   272→  gap: 6px;
   273→  cursor: pointer;
   274→  padding: 8px;
   275→}
   276→
   277→.mobile-menu-btn span {
   278→  display: block;
   279→  width: 28px;
   280→  height: 2.5px;
   281→  background-color: var(--clr-black);
   282→  transition: var(--transition);
   283→  pointer-events: none;
   284→}
   285→
   286→/* ==========================================================================
   287→   Hero Section
   288→   ========================================================================== */
   289→.hero {
   290→  min-height: 100vh;
   291→  display: flex;
   292→  align-items: center;
   293→  padding-top: 80px;
   294→  position: relative;
   295→  overflow: hidden;
   296→}
   297→
   298→.hero-container {
   299→  display: flex;
   300→  justify-content: center;
   301→  position: relative;
   302→  z-index: 1;
   303→}
   304→
   305→.hero-content {
   306→  max-width: 680px;
   307→}
   308→
   309→.hero-title {
   310→  font-size: 5.5rem;
   311→  font-weight: 900;
   312→  line-height: 1.05;
   313→  margin-bottom: 1.5rem;
   314→  letter-spacing: -3px;
   315→  color: var(--clr-black);
   316→}
   317→
   318→.hero-subtitle {
   319→  font-size: 1.2rem;
   320→  font-weight: 400;
   321→  max-width: 520px;
   322→  margin-bottom: 2.5rem;
   323→  color: #555;
   324→  line-height: 1.8;
   325→}
   326→
   327→.hero-actions {
   328→  display: flex;
   329→  gap: 1.25rem;
   330→}
   331→
   332→/* ==========================================================================
   333→   Section Headers
   334→   ========================================================================== */
   335→.section-header {
   336→  text-align: center;
   337→  margin-bottom: 3.5rem;
   338→}
   339→
   340→.section-title {
   341→  font-size: 3rem;
   342→  font-weight: 900;
   343→  margin-bottom: 1rem;
   344→  display: inline-block;
   345→  position: relative;
   346→  letter-spacing: -1px;
   347→}
   348→
   349→.section-title::after {
   350→  content: '';
   351→  position: absolute;
   352→  bottom: 6px;
   353→  left: -6px;
   354→  right: -6px;
   355→  height: 35%;
   356→  background-color: var(--clr-mint);
   357→  z-index: -1;
   358→  opacity: 0.6;
   359→}
   360→
   361→.section-desc {
   362→  font-size: 1.1rem;
   363→  max-width: 560px;
   364→  margin: 0 auto;
   365→  color: #555;
   366→  line-height: 1.8;
   367→}
   368→
   369→/* ==========================================================================
   370→   Bento Grid — Services
   371→   ========================================================================== */
   372→.bento-grid {
   373→  display: grid;
   374→  grid-template-columns: repeat(2, 1fr);
   375→  gap: 1.75rem;
   376→}
   377→
   378→.bento-card {
   379→  background-color: var(--clr-white);
   380→  border: var(--border-width) solid var(--clr-black);
   381→  padding: 2.5rem;
   382→  display: flex;
   383→  flex-direction: column;
   384→  box-shadow: var(--shadow-solid);
   385→  transition: var(--transition);
   386→  position: relative;
   387→  overflow: hidden;
   388→}
   389→
   390→.bento-card:hover {
   391→  transform: translateY(-4px);
   392→  box-shadow: 8px 8px 0px var(--clr-black);
   393→}
   394→
   395→.bento-card.bg-yellow {
   396→  background-color: var(--clr-yellow);
   397→}
   398→
   399→.bento-card.bg-mint {
   400→  background-color: var(--clr-mint);
   401→}
   402→
   403→.bento-icon {
   404→  font-size: 2.5rem;
   405→  margin-bottom: 1.25rem;
   406→  color: var(--clr-black);
   407→}
   408→
   409→.bento-card h3 {
   410→  font-size: 1.6rem;
   411→  font-weight: 800;
   412→  margin-bottom: 0.75rem;
   413→  line-height: 1.2;
   414→}
   415→
   416→.bento-card p {
   417→  font-size: 1rem;
   418→  line-height: 1.7;
   419→  margin-bottom: 0;
   420→  flex-grow: 1;
   421→  color: rgba(26, 26, 26, 0.8);
   422→}
   423→
   424→.bento-card.bg-yellow p,
   425→.bento-card.bg-mint p {
   426→  color: rgba(26, 26, 26, 0.85);
   427→}
   428→
   429→/* ==========================================================================
   430→   About Section
   431→   ========================================================================== */
   432→.about-container {
   433→  display: grid;
   434→  grid-template-columns: 1fr 1fr;
   435→  gap: 4rem;
   436→  align-items: center;
   437→}
   438→
   439→.about-desc {
   440→  font-size: 1.1rem;
   441→  margin-bottom: 2rem;
   442→  color: #444;
   443→  line-height: 1.8;
   444→}
   445→
   446→.about-list {
   447→  margin-bottom: 2rem;
   448→}
   449→
   450→.about-list li {
   451→  font-size: 1.05rem;
   452→  margin-bottom: 0.75rem;
   453→  display: flex;
   454→  align-items: center;
   455→  gap: 0.75rem;
   456→  font-weight: 500;
   457→}
   458→
   459→.check-icon {
   460→  display: flex;
   461→  align-items: center;
   462→  justify-content: center;
   463→  width: 22px;
   464→  height: 22px;
   465→  background-color: var(--clr-mint);
   466→  border: 2px solid var(--clr-black);
   467→  font-weight: 800;
   468→  font-size: 0.75rem;
   469→  flex-shrink: 0;
   470→}
   471→
   472→/* About Stats Card */
   473→.about-stats-card {
   474→  background-color: var(--clr-black);
   475→  color: var(--clr-white);
   476→  border: var(--border-width) solid var(--clr-black);
   477→  padding: 3rem 2.5rem;
   478→  box-shadow: 8px 8px 0px var(--clr-yellow);
   479→  display: flex;
   480→  flex-direction: column;
   481→  gap: 2rem;
   482→}
   483→
   484→.stat-item {
   485→  text-align: center;
   486→}
   487→
   488→.stat-number {
   489→  display: block;
   490→  font-size: 3.5rem;
   491→  font-weight: 900;
   492→  letter-spacing: -2px;
   493→  line-height: 1;
   494→  margin-bottom: 0.5rem;
   495→  color: var(--clr-yellow);
   496→}
   497→
   498→.stat-label {
   499→  display: block;
   500→  font-size: 0.85rem;
   501→  font-weight: 600;
   502→  text-transform: uppercase;
   503→  letter-spacing: 2px;
   504→  color: rgba(255, 255, 255, 0.7);
   505→}
   506→
   507→.stat-divider {
   508→  width: 40px;
   509→  height: 2px;
   510→  background-color: var(--clr-mint);
   511→  margin: 0 auto;
   512→  opacity: 0.5;
   513→}
   514→
   515→.mt-2 {
   516→  margin-top: 2rem;
   517→}
   518→
   519→/* ==========================================================================
   520→   Contact Section
   521→   ========================================================================== */
   522→.bg-dark {
   523→  background-color: var(--clr-black);
   524→  color: var(--clr-white);
   525→}
   526→
   527→.title-light {
   528→  color: var(--clr-white);
   529→}
   530→
   531→.title-light::after {
   532→  background-color: var(--clr-mint);
   533→  opacity: 0.35;
   534→}
   535→
   536→.contact-container {
   537→  display: flex;
   538→  flex-direction: column;
   539→  align-items: center;
   540→  text-align: center;
   541→  gap: 2.5rem;
   542→  padding: 3rem 0;
   543→}
   544→
   545→.contact-name {
   546→  font-size: 1.3rem;
   547→  font-weight: 700;
   548→  margin-bottom: 0.35rem;
   549→}
   550→
   551→.contact-role {
   552→  color: var(--clr-mint);
   553→  font-weight: 800;
   554→  text-transform: uppercase;
   555→  letter-spacing: 3px;
   556→  font-size: 0.8rem;
   557→  margin-bottom: 1.75rem;
   558→}
   559→
   560→.contact-header p {
   561→  font-size: 1.15rem;
   562→  opacity: 0.85;
   563→}
   564→
   565→/* ==========================================================================
   566→   Footer
   567→   ========================================================================== */
   568→.footer {
   569→  border-top: var(--border-width) solid var(--clr-black);
   570→  padding: 3rem 0 1.5rem;
   571→  background-color: var(--clr-white);
   572→}
   573→
   574→.footer-container {
   575→  display: grid;
   576→  grid-template-columns: 1fr;
   577→  margin-bottom: 2rem;
   578→}
   579→
   580→.footer-brand {
   581→  text-align: center;
   582→}
   583→
   584→.footer-logo {
   585→  justify-content: center;
   586→}
   587→
   588→.footer-logo-text {
   589→  font-size: 1.8rem;
   590→  letter-spacing: 3px;
   591→}
   592→
   593→.footer-tagline {
   594→  margin: 0.75rem auto 0;
   595→  font-size: 0.95rem;
   596→  color: var(--clr-grey);
   597→}
   598→
   599→.footer-bottom {
   600→  display: flex;
   601→  justify-content: center;
   602→  align-items: center;
   603→  padding-top: 1.5rem;
   604→  border-top: 1.5px solid rgba(26, 26, 26, 0.12);
   605→  font-weight: 500;
   606→  font-size: 0.85rem;
   607→  color: var(--clr-grey);
   608→}
   609→
   610→.footer-centered {
   611→  grid-template-columns: 1fr;
   612→  text-align: center;
   613→}
   614→
   615→.footer-bottom-centered {
   616→  display: block;
   617→  text-align: center;
   618→}
   619→
   620→/* ==========================================================================
   621→   Media Queries
   622→   ========================================================================== */
   623→@media (max-width: 992px) {
   624→
   625→  .hero-container,
   626→  .about-container,
   627→  .contact-container,
   628→  .footer-container {
   629→    grid-template-columns: 1fr;
   630→    text-align: center;
   631→  }
   632→
   633→  .hero-content {
   634→    text-align: center;
   635→    margin: 0 auto;
   636→  }
   637→
   638→  .hero-subtitle {
   639→    margin-left: auto;
   640→    margin-right: auto;
   641→  }
   642→
   643→  .about-list li {
   644→    justify-content: center;
   645→  }
   646→
   647→  .hero-actions {
   648→    justify-content: center;
   649→  }
   650→
   651→  .hero-title {
   652→    font-size: 3.5rem;
   653→  }
   654→
   655→  .bento-grid {
   656→    grid-template-columns: repeat(2, 1fr);
   657→  }
   658→
   659→  .about-stats-card {
   660→    flex-direction: row;
   661→    justify-content: center;
   662→    max-width: 500px;
   663→    margin: 0 auto;
   664→  }
   665→
   666→  .stat-divider {
   667→    width: 2px;
   668→    height: 40px;
   669→  }
   670→}
   671→
   672→@media (max-width: 768px) {
   673→  .nav-container .logo-img {
   674→    display: none;
   675→  }
   676→
   677→  .nav-links {
   678→    display: none;
   679→  }
   680→
   681→  .nav-links.active {
   682→    display: flex;
   683→    flex-direction: column;
   684→    position: absolute;
   685→    top: 100%;
   686→    left: 0;
   687→    width: 100%;
   688→    background-color: rgba(250, 250, 250, 0.98);
   689→    backdrop-filter: blur(12px);
   690→    -webkit-backdrop-filter: blur(12px);
   691→    padding: 2rem;
   692→    border-bottom: var(--border-width) solid var(--clr-black);
   693→    align-items: center;
   694→    gap: 1.5rem;
   695→    z-index: 999;
   696→  }
   697→
   698→  .mobile-menu-btn {
   699→    display: flex;
   700→    position: relative;
   701→    z-index: 1000;
   702→  }
   703→
   704→  .mobile-menu-btn.active span:nth-child(1) {
   705→    transform: translateY(8.5px) rotate(45deg);
   706→  }
   707→
   708→  .mobile-menu-btn.active span:nth-child(2) {
   709→    opacity: 0;
   710→  }
   711→
   712→  .mobile-menu-btn.active span:nth-child(3) {
   713→    transform: translateY(-8.5px) rotate(-45deg);
   714→  }
   715→
   716→  .hero-title {
   717→    font-size: 2.8rem;
   718→    letter-spacing: -1.5px;
   719→  }
   720→
   721→  .section-title {
   722→    font-size: 2rem;
   723→  }
   724→
   725→  .bento-grid {
   726→    grid-template-columns: 1fr;
   727→  }
   728→
   729→  .about-stats-card {
   730→    flex-direction: column;
   731→    max-width: 100%;
   732→  }
   733→
   734→  .stat-divider {
   735→    width: 40px;
   736→    height: 2px;
   737→  }
   738→
   739→  .footer-logo-text {
   740→    font-size: 1.5rem;
   741→  }
   742→
