     3→    // Navbar Scroll State
     4→    // =========================================================================
     5→    const navbar = document.getElementById('navbar');
     6→    
     7→    window.addEventListener('scroll', () => {
     8→        if (window.scrollY > 50) {
     9→            navbar.classList.add('scrolled');
    10→        } else {
