file.content:
/* ==========================================================================
   Experience Section
   ========================================================================== */
.experience-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 2rem;
}

.experience-item {
  background-color: var(--clr-white);
  border: var(--border-width) solid var(--clr-black);
  padding: 3rem 2rem;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  box-shadow: var(--shadow-solid);
  transition: var(--transition);
  position: relative;
}

.experience-item:hover {
  transform: translateY(-6px);
  box-shadow: 8px 8px 0px var(--clr-black);
  background-color: var(--clr-yellow);
}

.company-name {
  font-size: 2.2rem;
  font-weight: 900;
  letter-spacing: -1px;
  color: var(--clr-black);
  margin: 0;
}

.experience-item:hover .company-name {
  color: var(--clr-black);
}

/* Stagger animation for experience items */
.experience-grid .reveal:nth-child(2) {
  transition-delay: 0.1s;
}

.experience-grid .reveal:nth-child(3) {
  transition-delay: 0.2s;
}

.experience-grid .reveal:nth-child(4) {
  transition-delay: 0.3s;
}

/* ==========================================================================
   Contact Section
   ========================================================================== */
.bg-dark {
  background-color: var(--clr-black);
  color: var(--clr-white);
}

.title-light {
  color: var(--clr-white);
}

.title-light::after {
  background-color: var(--clr-mint);
  opacity: 0.35;
}

